(function () {
  var keywords = [
    "abstract", "async", "await", "boolean", "break", "case", "catch", "class", "const",
    "continue", "data", "def", "do", "else", "enum", "export", "extends", "false", "final",
    "finally", "for", "from", "fun", "function", "if", "import", "in", "interface", "is",
    "let", "new", "null", "object", "override", "package", "private", "protected", "public",
    "return", "sealed", "static", "suspend", "switch", "throw", "true", "try", "type",
    "val", "var", "void", "when", "while"
  ];
  var keywordPattern = new RegExp("\\b(" + keywords.join("|") + ")\\b", "g");

  function escapeHtml(value) {
    return value
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");
  }

  function wrapToken(kind, value) {
    return '<span class="hljs-' + kind + '">' + escapeHtml(value) + "</span>";
  }

  function highlightText(value) {
    var pattern = /(\/\/.*|#.*|\/\*[\s\S]*?\*\/|`(?:\\.|[^`])*`|"(?:\\.|[^"])*"|'(?:\\.|[^'])*'|\b\d+(?:\.\d+)?\b|\b[A-Z][A-Za-z0-9_]*(?=\b))/g;
    var output = "";
    var lastIndex = 0;
    var match;

    while ((match = pattern.exec(value)) !== null) {
      var plainText = value.slice(lastIndex, match.index);
      output += escapeHtml(plainText).replace(keywordPattern, '<span class="hljs-keyword">$1</span>');

      var token = match[0];
      if (/^(\/\/|#|\/\*)/.test(token)) {
        output += wrapToken("comment", token);
      } else if (/^[`"']/.test(token)) {
        output += wrapToken("string", token);
      } else if (/^\d/.test(token)) {
        output += wrapToken("number", token);
      } else {
        output += wrapToken("title", token);
      }
      lastIndex = pattern.lastIndex;
    }

    output += escapeHtml(value.slice(lastIndex)).replace(keywordPattern, '<span class="hljs-keyword">$1</span>');
    return output;
  }

  function highlightElement(block) {
    if (!block.classList.contains("hljs")) {
      block.classList.add("hljs");
    }
    block.innerHTML = highlightText(block.textContent || "");
  }

  window.hljs = window.hljs || {
    highlightElement: highlightElement
  };
})();
